import java.util.Scanner;

public class SafeBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read entire line

        // Define a maximum buffer size
        int maxSize = 10;

        // Truncate or pad the input to fit within the buffer size
        char[] buffer = new char[maxSize];
        int length = Math.min(name.length(), maxSize);

        name.getChars(0, length, buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

